import React, { useState, useEffect, useRef } from 'react';
import './App.css';
import ReactMarkdown from 'react-markdown';

const ws_url = 'ws://localhost:8001/ws';

function App() {
    const [messages, setMessages] = useState([]);
    const [socket, setSocket] = useState(null);
    const [inputMessage, setInputMessage] = useState('');
    const [conversationId, setConversationId] = useState('');
    const [minimized, setMinimized] = useState(true); // Start minimized
    const [showMenu, setShowMenu] = useState(false);
    const menuRef = useRef(null);
    const fileInputRef = useRef(null);
    const [userImage, setUserImage] = useState(null);

    useEffect(() => {
        // Create a WebSocket connection
        const ws = new WebSocket(`${ws_url}/abc-123`);

        ws.onopen = () => {
            console.log('WebSocket connection established');
        };

        ws.onmessage = (event) => {
            const data = JSON.parse(event.data);
            console.log('Received message:', data);

            // Update conversationId if it's present in the message
            if (data.conversation_id) {
                setConversationId(data.conversation_id);
            }

            // Append received message if it contains content
            if (data.type === 'chunk' && data.content) {
                setMessages(prevMessages => [
                    ...prevMessages, 
                    { content: data.content, id: Date.now(), sender: 'bot' }
                ]);
            }
        };

        ws.onerror = (error) => {
            console.error('WebSocket error:', error);
        };

        ws.onclose = () => {
            console.log('WebSocket connection closed');
        };

        // Store WebSocket connection in state
        setSocket(ws);

        // Cleanup on component unmount
        return () => {
            if (ws) {
                ws.close();
            }
        };
    }, []);

    // Click outside menu handler
    useEffect(() => {
        function handleClickOutside(event) {
            if (menuRef.current && !menuRef.current.contains(event.target)) {
                setShowMenu(false);
            }
        }

        document.addEventListener("mousedown", handleClickOutside);
        return () => {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, [menuRef]);

    // Send a message to the WebSocket server
    const sendMessage = () => {
        if (socket && socket.readyState === WebSocket.OPEN && inputMessage.trim() !== '') {
            const message = {
                query: inputMessage,
                conversation_id: conversationId, // Use the stored conversation ID
            };

            // Add user message to the chat
            setMessages(prevMessages => [
                ...prevMessages,
                { content: inputMessage, id: Date.now(), sender: 'user' }
            ]);

            socket.send(JSON.stringify(message));
            setInputMessage(''); // Clear input after sending
        } else {
            console.error('WebSocket is not open or message is empty');
        }
    };

    // Handle Enter key press
    const handleKeyPress = (e) => {
        if (e.key === 'Enter') {
            sendMessage();
        }
    };

    // Toggle chat minimize/maximize
    const toggleMinimize = () => {
        setMinimized(!minimized);
    };

    // Reset the chat
    const resetChat = () => {
        setConversationId('');
        setMessages([]);
        //setShowMenu(false);
        // You may want to notify the server about resetting the chat
        if (socket && socket.readyState === WebSocket.OPEN) {
            socket.send(JSON.stringify({ reset: true }));
        }
    };

    // Handle image upload
    const handleImageUpload = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setUserImage(reader.result);
            };
            reader.readAsDataURL(file);
        }
    };

    return (
        <div className={`chat-container ${minimized ? 'minimized' : ''}`}>
            {minimized ? (
                // Minimized circular view
                <div className="chat-logo" onClick={toggleMinimize}>
                    <img src="/logo.png" alt="Chat Logo" />
                </div>
            ) : (
                // Expanded chat view
                <div className="chat-expanded">
                    <div className="chat-header" onClick={toggleMinimize}>
                        <div className="avatar">
                            <img src="/assistance.jpg" alt="Bot Avatar" />
                        </div>
                        <div className="chat-options">
                            <button className="image-upload-btn" onClick={() => fileInputRef.current.click()}>
                                {userImage ? 'Change Image' : 'Upload Image'}
                                <input 
                                    type="file" 
                                    ref={fileInputRef} 
                                    style={{ display: 'none' }} 
                                    accept="image/*"
                                    onChange={handleImageUpload}
                                />
                            </button>
                        </div>
                        <div className="chat-controls" ref={menuRef}>
                            <button className="menu-button" onClick={(e) => {
                                e.stopPropagation();
                                setShowMenu(!showMenu);
                            }}>
                                ⋮
                            </button>
                            {showMenu && (
                                <div className="menu-dropdown">
                                    <button onClick={resetChat}>Reset Chat</button>
                                    <a href="https://analytics.example.com" target="_blank" rel="noopener noreferrer">Analytics</a>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="chat-messages">
                        {messages.map((message, index) => (
                            <div key={index} className={`message-wrapper ${message.sender}-wrapper`}>
                                <div className={`message ${message.sender}-message`}>
                                    {message.sender === 'user' && userImage && (
                                        <div className="user-image">
                                            <img src={userImage} alt="User" />
                                        </div>
                                    )}
                                    <ReactMarkdown>{message.content}</ReactMarkdown>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="chat-input">
                        <input
                            type="text"
                            value={inputMessage}
                            onChange={(e) => setInputMessage(e.target.value)}
                            onKeyPress={handleKeyPress}
                            placeholder="Type a message..."
                        />
                        <button onClick={sendMessage}>
                            <svg viewBox="0 0 24 24" width="24" height="24">
                                <path fill="#ffffff" d="M1.101 21.757L23.8 12.028 1.101 2.3l.011 7.912 13.623 1.816-13.623 1.817-.011 7.912z"></path>
                            </svg>
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

export default App;
